import functools

def validate_type(expected_type):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if not isinstance(args[0], expected_type):
                raise TypeError(f'Expected {expected_type.__name__}')
            return func(*args, **kwargs)
        return wrapper
    return decorator

@validate_type(int)
def double(x):
    return x * 2

print(double(5))
try:
    print(double('hello'))
except TypeError as e:
    print(f'Error: {e}')
